  try { var _gm = localStorage.getItem('ag_godmode_global'); window.__agGodMode = (_gm === '1'); } catch(_) { window.__agGodMode = false; }

  // Global GodMode interval - keeps HP/shield max + blocks contact damage anywhere
  setInterval(function() {
    if (!window.__agGodMode) return;
    try { if (Rt < 100) Rt = 100; } catch(_) {}
    // Zt (shields) not forced - let shield potions work correctly
    try { _s = performance.now() + 999999; } catch(_) {}
    try { li = 'idle'; ci = 0; } catch(_) {}
    try { tr = 0; } catch(_) {} // anti-stun anywhere
  }, 16);
  var agZombiesOnly = false; // Only attack zombies (skip dragons)
  var agWolvesOnly = false;  // Only attack wolves (wild_exp)
  // GodMode: intercepta dano v DUAS fontes:
  // 1. Dano remoto (servidor → WS presenceHub): wrappea Y.onmessage para remover campos php/psc/wmb
  // 2. Dano por contato (local, tickWildMobContactDamage): seta _s=Infinity impedindo o hit
