  function agBossSchedule(ms) {
    clearTimeout(agBossTickTimer);
    agBossTickTimer = setTimeout(agBossTick, ms);
  }

  function agBossStart() {
    if (agBossActive) return;
    agBossActive  = true;
    agBossState   = AG_BOSS_STATE.IDLE;
    agBossNavTarget = null;
    agBossLastSwingAt = 0;
    agBossLastClickAt = 0;
    agBossStuckAt = 0;
    agBossSchedule(300);
    // Atualizar botão
    try {
      var host = document.getElementById('ag-panel-host');
      var btn  = host && host.shadowRoot && host.shadowRoot.getElementById('ag-boss-btn');
      if (btn) { btn.textContent = '⏹ Parar Boss Hunt'; btn.style.background = '#7c3aed'; btn.style.color = '#fff'; btn.dataset.on = 'true'; }
    } catch(_) {}
    agBossSetStatus('⚔ Iniciado!');
    AG_BOSS_LOG.info('Boss Hunt iniciado');
  }

  function agBossStop() {
    agBossActive = false;
    agBossState  = AG_BOSS_STATE.IDLE;
    clearTimeout(agBossTickTimer);
    agBossTickTimer  = null;
    agBossNavTarget  = null;
    // Atualizar botão
    try {
      var host = document.getElementById('ag-panel-host');
      var btn  = host && host.shadowRoot && host.shadowRoot.getElementById('ag-boss-btn');
      if (btn) { btn.textContent = '▶ Iniciar Boss Hunt'; btn.style.background = '#1e293b'; btn.style.color = '#8a93a8'; btn.dataset.on = 'false'; }
    } catch(_) {}
    agBossSetStatus('Desligado');
    AG_BOSS_LOG.info('Boss Hunt parado');
  }

  function agBossToggle() { agBossActive ? agBossStop() : agBossStart(); }

  // ── Auto-restore após restart ──────────────────────────────────────────────
  // Salva estado ativo no localStorage e restaura automaticamente
  // quando (re != null) fica true (player passou pela fila e entrou)

  const AG_STORAGE_KEY = 'kintara_ag_state';

  function agSaveState() {
    try {
      const state = { mode: agMode, active: agActive, optimizedFarm: agOptimizedFarm, ts: Date.now() };
      localStorage.setItem(AG_STORAGE_KEY, JSON.stringify(state));
    } catch (_) {}
    // Persiste optimizedFarm também no agOptCfg — sem timeout v 10min
    try {
      agOptCfg.optimizedFarmActive = agOptimizedFarm;
      agOptSaveCfg();
    } catch (_) {}
  }

  function agLoadState() {
    try {
      const raw = localStorage.getItem(AG_STORAGE_KEY);
      if (!raw) return null;
      const s = JSON.parse(raw);
      // Ignora estado com mais v 10 minutos (restart muito antigo)
      if (Date.now() - (s.ts || 0) > 60 * 60 * 1000) return null; // 1h TTL
      return s;
    } catch (_) { return null; }
  }

  function agClearSavedState() {
    try { localStorage.removeItem(AG_STORAGE_KEY); } catch (_) {}
  }

