    shadow.appendChild(styleEl);
    shadow.appendChild(panel);

    const $ = (id) => shadow.getElementById(id);
    agStatusEl = $('ag-status');
    agBtnEl    = $('ag-btn');
    agHintEl   = $('ag-hint');

    // ── Tab switching ─────────────────────────────────────────────────────
    function agSwitchTab(tabName) {
      shadow.querySelectorAll('#ag-tab-grid .ag-tab').forEach(function(t) { t.classList.toggle('active', t.dataset.tab===tabName); });
      shadow.querySelectorAll('.ag-pane').forEach(function(p) { p.classList.toggle('active', p.dataset.pane===tabName); });
      try { localStorage.setItem('ag_active_tab', tabName); } catch(_) {}
      // Popular sell pane quando ativado
      if (tabName === 'sell') { try { agBuildSellPaneItems(shadow); } catch(_) {} }
      if (tabName === 'lottery') { try { agLotteryRenderTab(shadow); } catch(_) {} }
      if (tabName === 'storage') {
        try { agStorageRenderTab(shadow); } catch(_) {}
        try { agStorageRenderAutoDeposit(shadow); } catch(_) {}
      }
      if (tabName === 'pvp') {
        try { agPvpRenderList(shadow); } catch(_) {}
      }
      if (tabName === 'boss') {
        try {
          var bossGodChk2 = shadow.getElementById('ag-boss-godmode');
          if (bossGodChk2) bossGodChk2.checked = agBossGodMode;
          var bossNoStunChk2 = shadow.getElementById('ag-boss-no-stun');
          if (bossNoStunChk2) bossNoStunChk2.checked = agBossNoStun;
          var bossRushChk2 = shadow.getElementById('ag-boss-rush');
          if (bossRushChk2) bossRushChk2.checked = agBossRush;
        } catch(_) {}
      }
      if (tabName === 'ember') {
        try { agEmberRenderAutoDepositList(shadow); } catch(_) {}
        try {
          var egc = shadow.getElementById('ag-ember-godmode');
          if (egc) {
            egc.checked = !!window.__agGodMode;
            egc.onchange = function() {
              window.__agGodMode = egc.checked;
              try { localStorage.setItem('ag_godmode_global', egc.checked ? '1' : '0'); } catch(_) {}
              // Sync with global godmode checkbox if visible
              try { var gb = document.getElementById('ag-godmode-global'); if (gb) gb.checked = egc.checked; } catch(_) {}
            };
          }
          var ebc = shadow.getElementById('ag-ember-bossmode');
          if (ebc) ebc.checked = window.__agGodMode;
          var emc = shadow.getElementById('ag-ember-ignore-mobs');
          if (emc) emc.checked = agEmberIgnoreMobs;
          try {
            var ekc = shadow.getElementById('ag-ember-kite');
            var hkc = shadow.getElementById('ag-hunt-kite-check');
            if (ekc && hkc) ekc.checked = hkc.checked;
          } catch(_) {}
        } catch(_) {}
      }
    }
    shadow.querySelectorAll('#ag-tab-grid .ag-tab').forEach(function(tab) {
      tab.addEventListener('click', function() { agSwitchTab(tab.dataset.tab); });
    });
    // Restaurar aba salva
    try { var _savedTab = localStorage.getItem('ag_active_tab'); if(_savedTab) agSwitchTab(_savedTab); } catch(_) {}

    // ag-cfg-join-club2 sync com ag-cfg-join-club
    var jc1=$('ag-cfg-join-club'), jc2=$('ag-cfg-join-club2');
    if(jc1&&jc2){ jc2.checked=jc1.checked; jc2.addEventListener('change',function(e){jc1.checked=e.target.checked;jc1.dispatchEvent(new Event('change'));}); jc1.addEventListener('change',function(){jc2.checked=jc1.checked;}); }

    // ── AutoSell pane: popular items e handlers ─────────────────────────────
    function agBuildSellPaneItems(sh) {
      var list = sh ? sh.getElementById('as-item-list') : null;
      if (!list) return;
      var cfg = agLoadAutoSellConfig ? agLoadAutoSellConfig() : {};
      var items = ['wood','stone','coal','gold','metal','fish','cooked_fish_meat','brute_horn','molten_rock'];
      var labels = {wood:'Wood',stone:'Stone',coal:'Coal',gold:'Gold',metal:'Metal',fish:'Fish',cooked_fish_meat:'Cooked Fish',brute_horn:'Brute Horn',molten_rock:'Molten Rock'};
      list.innerHTML = items.map(function(type) {
        var c = cfg[type] || {};
        var ic = (cfg.items && cfg.items[type]) || agDefaultItemSellCfg();
        var checked = ic.active ? 'checked' : '';
        var inpS = 'width:100%;box-sizing:border-box;background:rgba(255,255,255,0.08);border:1px solid rgba(255,255,255,0.16);border-radius:4px;color:#d4d8e2;font-size:10px;padding:2px 5px;outline:none;font-family:inherit;margin-top:1px';
        var lblS = 'font-size:9px;color:#8a93a8;display:block;margin-bottom:1px';
        return '<div style="margin-bottom:2px">' +
          '<div class="as-item-row" style="display:flex;align-items:center;gap:6px;padding:4px 6px;border-radius:5px;background:rgba(255,255,255,0.04);border:1px solid rgba(255,255,255,0.07)">' +
            '<input type="checkbox" data-as-item="' + type + '" style="width:13px;height:13px;accent-color:#f97316;cursor:pointer;flex-shrink:0" ' + checked + '>' +
            '<span class="as-item-name" style="flex:1;font-size:11px;color:' + (ic.active?'#d4d8e2':'#556') + ';user-select:none">' + labels[type] + '</span>' +
            '<button class="as-cfg-btn" data-as-cfg="' + type + '" style="background:rgba(255,255,255,0.07);border:1px solid rgba(255,255,255,0.13);border-radius:4px;color:#8a93a8;font-size:10px;padding:2px 6px;cursor:pointer;flex-shrink:0" title="Configurar ' + labels[type] + '">&#9881;</button>' +
          '</div>' +
          '<div class="as-item-cfg" data-cfg-for="' + type + '" style="display:none;padding:5px 8px 6px;background:rgba(255,200,100,0.04);border:1px solid rgba(255,200,100,0.12);border-radius:0 0 5px 5px;margin-top:-1px">' +
            '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px"><span style="font-size:9px;font-weight:700;color:#fbbf24">' + labels[type] + '</span><button data-cfg-close="' + type + '" style="background:none;border:none;color:#556;font-size:11px;cursor:pointer;padding:0 2px" title="Fechar">✕</button></div>' +
            '<div style="margin-bottom:4px"><label style="' + lblS + '">Qtd mínima p/ vender</label><input data-cfg-field="threshold" data-cfg-type="' + type + '" type="number" min="100" step="100" style="' + inpS + '" value="' + ic.threshold + '"></div>' +
            '<div style="margin-bottom:4px"><label style="' + lblS + '">Keep (reservar)</label><input data-cfg-field="keep" data-cfg-type="' + type + '" type="number" min="0" step="100" style="' + inpS + '" value="' + (ic.keep||0) + '" placeholder="0 = vende tudo"></div>' +
            '<label style="display:flex;align-items:center;gap:4px;cursor:pointer;margin-bottom:3px;font-size:10px"><input type="checkbox" data-cfg-field="useFloor" data-cfg-type="' + type + '" style="accent-color:#f97316"' + (ic.useFloor?' checked':'') + '>Floor Price (−$0.01)</label>' +
            '<div data-cfg-floor-opts="' + type + '" style="' + (ic.useFloor?'':'display:none') + ';margin-left:16px;margin-bottom:3px">' +
              '<label style="display:flex;align-items:center;gap:4px;cursor:pointer;font-size:10px;margin-bottom:2px"><input type="checkbox" data-cfg-field="useMinFloor" data-cfg-type="' + type + '" style="accent-color:#f97316"' + (ic.useMinFloor?' checked':'') + '>Check Min Floor</label>' +
              '<div data-cfg-min-row="' + type + '" style="' + (ic.useMinFloor?'':'display:none') + '"><label style="' + lblS + '">Min Floor $/Ae</label><input data-cfg-field="minFloor" data-cfg-type="' + type + '" type="text" inputmode="decimal" placeholder="0.00006" style="' + inpS + '" value="' + (ic.minFloor||'') + '"></div>' +
            '</div>' +
            '<div data-cfg-fixed-row="' + type + '" style="' + (ic.useFloor?'opacity:.3;pointer-events:none':'') + ';margin-bottom:3px"><label style="' + lblS + '">Preço fixo $/Ae (−$0.01)</label><input data-cfg-field="fixedPrice" data-cfg-type="' + type + '" type="number" step="0.00000001" min="0" placeholder="0.00010000" style="' + inpS + '" value="' + (ic.fixedPrice||'') + '"></div>' +
            '<button data-cfg-save="' + type + '" style="width:100%;padding:3px 0;border-radius:4px;border:none;background:#f97316;color:#fff;font-size:10px;font-weight:700;cursor:pointer">&#10003; Salvar</button>' +
          '</div>' +
        '</div>';
      }).join('');
      // handlers
      list.querySelectorAll('input[data-as-item]').forEach(function(el) {
        el.addEventListener('change', function() {
          if (!agLoadAutoSellConfig) return;
          var cfg2 = agLoadAutoSellConfig();
          if (!cfg2.items) cfg2.items = {};
          if (!cfg2.items[el.dataset.asItem]) cfg2.items[el.dataset.asItem] = agDefaultItemSellCfg();
          cfg2.items[el.dataset.asItem].active = el.checked;
          agSaveAutoSellConfig(cfg2);
          try { agBuildSellPaneItems(sh); } catch(_) {}
        });
      });
      list.querySelectorAll('[data-as-cfg]').forEach(function(el) {
        el.addEventListener('click', function() {
          var type = el.dataset.asCfg;
          var cfgDiv = list.querySelector('[data-cfg-for="' + type + '"]');
          if (!cfgDiv) return;
          // Toggle expand/collapse
          var open = cfgDiv.style.display !== 'none';
          // Close all others first
          list.querySelectorAll('.as-item-cfg').forEach(function(d) { d.style.display = 'none'; });
          if (!open) cfgDiv.style.display = '';
        });
      });
      // Close button (X) inside config
      list.querySelectorAll('[data-cfg-close]').forEach(function(el) {
        el.addEventListener('click', function() {
          var cfgDiv = list.querySelector('[data-cfg-for="' + el.dataset.cfgClose + '"]');
          if (cfgDiv) cfgDiv.style.display = 'none';
        });
      });
      // Floor checkbox toggle
      list.querySelectorAll('[data-cfg-field="useFloor"]').forEach(function(el) {
        el.addEventListener('change', function() {
          var t = el.dataset.cfgType;
          var opts = list.querySelector('[data-cfg-floor-opts="' + t + '"]');
          var fr = list.querySelector('[data-cfg-fixed-row="' + t + '"]');
          if (opts) opts.style.display = el.checked ? '' : 'none';
          if (fr) { fr.style.opacity = el.checked ? '0.3' : '1'; fr.style.pointerEvents = el.checked ? 'none' : 'auto'; }
        });
      });
      list.querySelectorAll('[data-cfg-field="useMinFloor"]').forEach(function(el) {
        el.addEventListener('change', function() {
          var t = el.dataset.cfgType;
          var Tn = list.querySelector('[data-cfg-min-row="' + t + '"]');
          if (Tn) Tn.style.display = el.checked ? '' : 'none';
        });
      });
      // Save button
      list.querySelectorAll('[data-cfg-save]').forEach(function(btn) {
        btn.addEventListener('click', function() {
          var t = btn.dataset.cfgSave;
          var c2 = agLoadAutoSellConfig();
          if (!c2.items) c2.items = {};
          var rawMin = (list.querySelector('[data-cfg-field="minFloor"][data-cfg-type="' + t + '"]')?.value || '').replace(',','.');
          c2.items[t] = Object.assign(c2.items[t] || agDefaultItemSellCfg(), {
            threshold:   Number(list.querySelector('[data-cfg-field="threshold"][data-cfg-type="' + t + '"]')?.value) || 3000,
            keep:        Number(list.querySelector('[data-cfg-field="keep"][data-cfg-type="' + t + '"]')?.value) || 0,
            useFloor:    !!list.querySelector('[data-cfg-field="useFloor"][data-cfg-type="' + t + '"]')?.checked,
            fixedPrice:  Number(list.querySelector('[data-cfg-field="fixedPrice"][data-cfg-type="' + t + '"]')?.value) || 0,
            useMinFloor: !!list.querySelector('[data-cfg-field="useMinFloor"][data-cfg-type="' + t + '"]')?.checked,
            minFloor:    parseFloat(rawMin) || 0,
          });
          agSaveAutoSellConfig(c2);
          // Flash feedback
          btn.textContent = '✓ Salvo!'; btn.style.background = '#27ae60';
          setTimeout(function() { btn.innerHTML = '&#10003; Salvar'; btn.style.background = '#f97316'; }, 1200);
        });
      });

      // ── Pets / Cosmetics / Mounts list (auto-sell style) ──────────────────
      var specList = sh.getElementById('as-special-list');
      if (specList) {
        var specItems = agGetSpecialSellItems();
        if (specItems.length === 0) {
          specList.innerHTML = '<div style="font-size:9px;color:#556;text-align:center;padding:3px 0">Nenhum item especial no inventário</div>';
        } else {
          var specCfg = agLoadAutoSellConfig();
          if (!specCfg.items) specCfg.items = {};
          var inpSS = 'width:100%;box-sizing:border-box;background:rgba(255,255,255,0.08);border:1px solid rgba(255,255,255,0.16);border-radius:4px;color:#d4d8e2;font-size:10px;padding:2px 5px;outline:none;margin-top:1px';
          var lblSS = 'font-size:9px;color:#8a93a8;display:block;margin-bottom:1px';
          specList.innerHTML = specItems.map(function(it) {
            var ic = specCfg.items[it.type] || agDefaultItemSellCfg();
            var checked = ic.active ? 'checked' : '';
            return '<div style="margin-bottom:2px">' +
              '<div style="display:flex;align-items:center;gap:5px;padding:3px 5px;border-radius:4px;background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.06)">' +
                '<input type="checkbox" data-spec-item="' + it.type + '" style="width:12px;height:12px;accent-color:#a78bfa;cursor:pointer" ' + checked + '>' +
                '<span style="flex:1;font-size:9px;color:' + (ic.active?'#d4d8e2':'#556') + ';overflow:hidden;text-overflow:ellipsis;white-space:nowrap">' + it.icon + ' ' + agFormatItemName(it.type) + ' <span style="color:#64748b">x' + it.count + '</span></span>' +
                '<button class="spec-cfg-btn" data-spec-cfg="' + it.type + '" style="background:rgba(255,255,255,0.07);border:1px solid rgba(255,255,255,0.13);border-radius:3px;color:#8a93a8;font-size:9px;padding:1px 5px;cursor:pointer">&#9881;</button>' +
              '</div>' +
              '<div class="spec-item-cfg" data-spec-cfg-for="' + it.type + '" style="display:none;padding:4px 6px;background:rgba(167,139,250,0.04);border:1px solid rgba(167,139,250,0.12);border-radius:0 0 4px 4px;margin-top:-1px">' +
                '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:3px"><span style="font-size:8px;font-weight:700;color:#a78bfa">' + agFormatItemName(it.type) + '</span><button data-spec-cfg-close="' + it.type + '" style="background:none;border:none;color:#556;font-size:10px;cursor:pointer;padding:0">✕</button></div>' +
                '<label style="display:flex;align-items:center;gap:4px;cursor:pointer;margin-bottom:3px;font-size:9px"><input type="checkbox" data-spec-field="useFloor" data-spec-type="' + it.type + '" style="accent-color:#a78bfa"' + (ic.useFloor?' checked':'') + '>Floor Price (−$0.01)</label>' +
                '<div data-spec-fixed-row="' + it.type + '" style="' + (ic.useFloor?'opacity:.3;pointer-events:none':'') + ';margin-bottom:3px"><label style="' + lblSS + '">Preço fixo $ (total)</label><input data-spec-field="fixedPrice" data-spec-type="' + it.type + '" type="number" step="0.01" min="0.01" placeholder="ex: 5.00" style="' + inpSS + '" value="' + (ic.fixedPrice||'') + '"></div>' +
                '<button data-spec-save="' + it.type + '" data-spec-kind="' + it.kind + '" style="width:100%;padding:2px 0;border-radius:3px;border:none;background:#a78bfa;color:#fff;font-size:9px;font-weight:700;cursor:pointer">&#10003; Salvar</button>' +
              '</div>' +
            '</div>';
          }).join('');
          // Checkbox handlers
          specList.querySelectorAll('[data-spec-item]').forEach(function(el) {
            el.addEventListener('change', function() {
              var c2 = agLoadAutoSellConfig();
              if (!c2.items) c2.items = {};
              if (!c2.items[el.dataset.specItem]) c2.items[el.dataset.specItem] = agDefaultItemSellCfg();
              c2.items[el.dataset.specItem].active = el.checked;
              c2.items[el.dataset.specItem]._slotKind = specItems.find(function(x){return x.type===el.dataset.specItem;})?.kind || 'inv';
              agSaveAutoSellConfig(c2);
            });
          });
          // Gear toggle
          specList.querySelectorAll('[data-spec-cfg]').forEach(function(el) {
            el.addEventListener('click', function() {
              var cfgDiv = specList.querySelector('[data-spec-cfg-for="' + el.dataset.specCfg + '"]');
              if (!cfgDiv) return;
              var open = cfgDiv.style.display !== 'none';
              specList.querySelectorAll('.spec-item-cfg').forEach(function(d){d.style.display='none';});
              if (!open) cfgDiv.style.display = '';
            });
          });
          // Close buttons
          specList.querySelectorAll('[data-spec-cfg-close]').forEach(function(el) {
            el.addEventListener('click', function() {
              var cfgDiv = specList.querySelector('[data-spec-cfg-for="' + el.dataset.specCfgClose + '"]');
              if (cfgDiv) cfgDiv.style.display = 'none';
            });
          });
          // Floor toggle
          specList.querySelectorAll('[data-spec-field="useFloor"]').forEach(function(el) {
            el.addEventListener('change', function() {
              var fr = specList.querySelector('[data-spec-fixed-row="' + el.dataset.specType + '"]');
              if (fr) { fr.style.opacity = el.checked ? '0.3' : '1'; fr.style.pointerEvents = el.checked ? 'none' : 'auto'; }
            });
          });
          // Save
          specList.querySelectorAll('[data-spec-save]').forEach(function(btn) {
            btn.addEventListener('click', function() {
              var t = btn.dataset.specSave;
              var c2 = agLoadAutoSellConfig();
              if (!c2.items) c2.items = {};
              c2.items[t] = Object.assign(c2.items[t] || agDefaultItemSellCfg(), {
                useFloor:   !!specList.querySelector('[data-spec-field="useFloor"][data-spec-type="' + t + '"]')?.checked,
                fixedPrice: Number(specList.querySelector('[data-spec-field="fixedPrice"][data-spec-type="' + t + '"]')?.value) || 0,
                _slotKind:  btn.dataset.specKind || 'inv',
              });
              agSaveAutoSellConfig(c2);
              btn.textContent = '✓ Salvo!'; btn.style.background = '#27ae60';
              setTimeout(function(){btn.innerHTML='&#10003; Salvar';btn.style.background='#a78bfa';},1200);
            });
          });
        }
      }

      // Sync toggle button
      var tog = sh.getElementById('as-toggle');
      if (tog) {
        // Remove listeners antigos clonando o botão
        var newTog = tog.cloneNode(true);
        tog.parentNode.replaceChild(newTog, tog);
        tog = newTog;
        tog.dataset.on = agAutoSellActive ? 'true' : 'false';
        tog.innerHTML = agAutoSellActive ? '&#9646;&#9646; Parar Auto-Venda' : '&#9654; Ativar Auto-Venda';
        tog.addEventListener('click', function() {
          if (agAutoSellActive) {
            agAutoSellStop();
            agAutoSellPendingStart = false;
            tog.dataset.on='false'; tog.innerHTML='&#9654; Ativar Auto-Venda';
          } else {
            agAutoSellStart(); // já chama agRunAutoSell internamente
            tog.dataset.on='true'; tog.innerHTML='&#9646;&#9646; Parar Auto-Venda';
          }
        });
      }
      // Sell only Daily Done checkbox
      var dailyChk = sh.getElementById('as-daily-check');
      if (dailyChk) {
        var newDailyChk = dailyChk.cloneNode(true);
        dailyChk.parentNode.replaceChild(newDailyChk, dailyChk);
        dailyChk = newDailyChk;
        try { agSellOnlyDailyDone = localStorage.getItem('ag_sell_daily_check') !== '0'; } catch(_) {}
        dailyChk.checked = agSellOnlyDailyDone;
        dailyChk.addEventListener('change', function() {
          agSellOnlyDailyDone = dailyChk.checked;
          try { localStorage.setItem('ag_sell_daily_check', agSellOnlyDailyDone ? '1' : '0'); } catch(_) {}
        });
      }
      // blacklist btn
      var blBtn = sh.getElementById('as-blacklist-btn');
      if (blBtn) blBtn.addEventListener('click', function() { try { agOpenAutoSellHud(); } catch(_) {} });
    }
    // Popular imediatamente se aba sell já está ativa
    if (localStorage.getItem('ag_active_tab') === 'sell') { try { agBuildSellPaneItems(shadow); } catch(_) {} }

    // ── Performance handlers ──────────────────────────────────────────────
    shadow.querySelectorAll('.ag-pfps').forEach(function(b){ b.addEventListener('click',function(){agPerfSetFps(parseInt(b.dataset.fps||0));}); });
    shadow.querySelectorAll('.ag-pqual').forEach(function(b){ b.addEventListener('click',function(){agPerfSetQuality(b.dataset.quality);}); });
    shadow.querySelectorAll('.ag-pfilt').forEach(function(b){ b.addEventListener('click',function(){ agPerfCfg.filter=b.dataset.filter; agPerfFilter(b.dataset.filter); agPerfSave(); agPerfUpdateUI(); }); });
    var bgEl=$('ag-perf-bg'); if(bgEl) bgEl.addEventListener('change',function(e){agPerfSetBg(e.target.checked);});
    var hudEl=$('ag-perf-hud'); if(hudEl) hudEl.addEventListener('change',function(e){agPerfSetHud(e.target.checked);});
    var flashEl=$('ag-perf-flash'); if(flashEl) flashEl.addEventListener('change',function(e){agPerfCfg.flashFix=e.target.checked;agPerfFlashFix(e.target.checked);agPerfSave();});
    var ctxEl=$('ag-perf-ctx'); if(ctxEl) ctxEl.addEventListener('change',function(e){agPerfCfg.ctxGuard=e.target.checked;agPerfSave();});
    var statsEl=$('ag-perf-stats'); if(statsEl) statsEl.addEventListener('change',function(e){agPerfCfg.sessionStats=e.target.checked;agPerfSave();});
    agPerfUpdateUI();



    // ── Collapsible sections ──────────────────────────────────────────────────
    function makeCollapsible(hdrId, bodyId, chevId) {
      var hdr  = $(hdrId);
      var body = $(bodyId);
      var chev = $(chevId);
      if (!hdr || !body) return;
      hdr.addEventListener('click', function() {
        var open = body.classList.contains('open');
        body.classList.toggle('open', !open);
        body.classList.toggle('closed', open);
        if (chev) chev.classList.toggle('open', !open);
      });
    }
    makeCollapsible('ag-farm-hdr',    'ag-farm-body',    'ag-farm-chev');
    makeCollapsible('ag-startup-hdr', 'ag-startup-body', 'ag-startup-chev');
    makeCollapsible('ag-realm-hdr',   'ag-realm-body',   'ag-realm-chev');
    makeCollapsible('ag-minihud-hdr', 'ag-minihud-body', 'ag-minihud-chev');
    // Inicia a seção MINI HUDs aberta por padrão
    var _mhBody = $('ag-minihud-body'); var _mhChev = $('ag-minihud-chev');
    if (_mhBody) { _mhBody.classList.add('open'); _mhBody.classList.remove('closed'); }
    if (_mhChev) _mhChev.classList.add('open');
    makeCollapsible('ag-hunt-hdr',    'ag-hunt-body',     'ag-hunt-chev');

    // ── Minimize (clique no titulo) ───────────────────────────────────────────
    var mini = false;
    function setMini(v) {
      mini = v;
      panel.className = v ? 'mini' : 'expanded';
      agUpdateMiniView();
      var btn = $('ag-minimize-btn');
      if (btn) btn.textContent = v ? '+' : 'M';
    }
    // [CAM] button toggle center camera
    function agUpdateCamBtn() {
      var btn = $('ag-camera-btn');
      if (!btn) return;
      var on = !!z.centerCamera;
      btn.style.background = on ? 'rgba(110,231,160,0.15)' : 'rgba(255,255,255,0.08)';
      btn.style.borderColor = on ? 'rgba(110,231,160,0.5)' : 'rgba(255,255,255,0.18)';
      btn.style.color       = on ? '#6ee7a0' : '#8a93a8';
    }
    $('ag-camera-btn').addEventListener('click', function(e) {
      e.stopPropagation();
      z.centerCamera = !z.centerCamera;
      le();
      agUpdateCamBtn();
    });
    agUpdateCamBtn();

    // [M] button minimiza/expande
    $('ag-minimize-btn').addEventListener('click', function(e) {
      e.stopPropagation();
      setMini(!mini);
    });
    // Painel inicia expandido mas seções recolhidas
    // Update [M] button label based on state
    function updateMiniBtnLabel() {
      var btn = $('ag-minimize-btn');
      if (btn) btn.textContent = mini ? '+' : 'M';
    }

    // ── Mini view ─────────────────────────────────────────────────────────────
    var agMiniStatsEl = $('ag-mini-stats');
    var agMiniBtnEl   = $('ag-mini-btn');
    function agUpdateMiniView() {
      if (!agMiniBtnEl) return;
      agMiniBtnEl.dataset.on = agActive ? 'true' : 'false';
      agMiniBtnEl.innerHTML = agActive ? '&#9646;&#9646; Parar' : '&#9654; Iniciar';
    }
    if (agMiniBtnEl) agMiniBtnEl.addEventListener('click', function() { agToggle(); });
    // Mini stats click expands
    if (agMiniStatsEl) agMiniStatsEl.addEventListener('click', function() { setMini(false); });

    // ── Mode select ───────────────────────────────────────────────────────────
    $('ag-mode').addEventListener('change', function(e) {
      agMode = e.target.value; agRefreshHint(); agSaveState();
      if (agActive) { agStatsReset(); agStartRateTimer(); }
      // Farm Otimizado é sempre ativo no modo 'all'
      if (agMode === 'all' && !agOptimizedFarm) {
        agOptimizedFarm = true;
        agOptUpdateIndicator();
        try { agOptFarmRefreshFloors(); } catch(_) {}
        AG_OPT_LOG.warn('Auto-ATIVADO (modo All selecionado)');
      }
      // Mostrar/esconder Auto Cook Fish
      var fishCookRow = $('ag-fish-cook-row');
      if (fishCookRow) fishCookRow.style.display = agMode === 'fish' ? '' : 'none';
      var stealthRow = $('ag-stealth-fish-row');
      if (stealthRow) stealthRow.style.display = agMode === 'fish' ? '' : 'none';
      var ghostRow = $('ag-ghost-fish-row');
      if (ghostRow) ghostRow.style.display = agMode === 'fish' ? '' : 'none';
    });

    // Auto Cook Fish checkbox
    var autoCookEl = $('ag-auto-cook');
    if (autoCookEl) {
      autoCookEl.checked = agAutoCookFish;
      autoCookEl.addEventListener('change', function(e) {
        agAutoCookFish = e.target.checked;
        agSaveState();
      });
    }
    // Estado inicial do row
    // Stealth Fish checkbox
    var stealthChk = $('ag-stealth-fish');
    if (stealthChk) {
      try { agStealthFish = localStorage.getItem('ag_stealth_fish') === '1'; } catch(_) {}
      stealthChk.checked = agStealthFish;
      stealthChk.addEventListener('change', function() {
        agStealthFish = stealthChk.checked;
        try { localStorage.setItem('ag_stealth_fish', agStealthFish ? '1' : '0'); } catch(_) {}
        if (agStealthFish && agActive && agMode === 'fish') agStartStealthLoop();
        else agStopStealthLoop();
      });
    }
    var stealthRowInit = $('ag-stealth-fish-row');
    if (stealthRowInit) stealthRowInit.style.display = agMode === 'fish' ? '' : 'none';

    // Ghost Fish checkbox
    var ghostChk = $('ag-ghost-fish');
    if (ghostChk) {
      try { agGhostFish = localStorage.getItem('ag_ghost_fish') === '1'; } catch(_) {}
      ghostChk.checked = agGhostFish;
      ghostChk.addEventListener('change', function() {
        agGhostFish = ghostChk.checked;
        try { localStorage.setItem('ag_ghost_fish', agGhostFish ? '1' : '0'); } catch(_) {}
        if (agGhostFish) agInstallGhostFishHook();
      });
    }
    var ghostRowInit = $('ag-ghost-fish-row');
    if (ghostRowInit) ghostRowInit.style.display = agMode === 'fish' ? '' : 'none';

    var fishCookRowInit = $('ag-fish-cook-row');
    if (fishCookRowInit) fishCookRowInit.style.display = agMode === 'fish' ? '' : 'none';

    // ── Server & Zone selector ───────────────────────────────────────────────
    (function loadServers() {
      var sel  = $('ag-server-sel');
      var zoneSel = $('ag-zone-sel');
      if (!sel) return;

      // Restore saved preferences
      var savedServer = '';
      var savedZone   = '';
      try {
        savedServer = localStorage.getItem('kintara_ag_preferred_server') || '';
        savedZone   = localStorage.getItem('kintara_ag_preferred_zone')   || '';
      } catch(_) {}
      if (zoneSel && savedZone) zoneSel.value = savedZone;

      // ── Helper: get preferred zone from UI ───────────────────────────────
      function agGetPreferredZone() {
        try {
          return localStorage.getItem('kintara_ag_preferred_zone') || '';
        } catch(_) { return ''; }
      }

      // ── Helper: find zone button in new server selection UI ─────────────
      function agFindZoneBtn(zone) {
        if (!zone) return null;
        // Map of valid zones - never include club/premium zones
        // Map of valid zones - never include club/premium zones
        var zoneMap = { 'NA': ['NA','NORTH AMERICA'], 'EUR': ['EUR','EUROPE'], 'ASIA': ['ASIA','ASIA PACIFIC'] };
        var clubKeywords = ['club','premium','member','subscribe'];
        var clubKeywords = ['club','premium','member','subscribe'];
        var labels = zoneMap[zone.toUpperCase()] || [zone.toUpperCase()];
        return Array.from(document.querySelectorAll('button')).find(function(b) {
          var txt = (b.textContent || '').trim().toUpperCase();
          if (clubKeywords.some(function(k) { return txt.toLowerCase().indexOf(k) !== -1; })) return false;
          if (clubKeywords.some(function(k) { return txt.toLowerCase().indexOf(k) !== -1; })) return false;
          return labels.some(function(l) { return txt === l || txt.startsWith(l); });
        }) || null;
      }

      // ── Helper: get all server items from new or old UI ──────────────────
      function agGetServerItems() {
        // New UI: server list cards after zone selection
        var items = Array.from(document.querySelectorAll(
          'button.kintara-server-card, .kintara-server-select-btn, ' +
          '[class*="server-card"], [class*="server-item"]'
        ));
        if (!items.length) {
          // Fallback: any clickable element with "SERVER \d" text
          items = Array.from(document.querySelectorAll('button, [role="button"]')).filter(function(el) {
            return /SERVER\s*\d+/i.test(el.textContent || '');
          });
        }
        return items;
      }

      // ── Populate server dropdown from API ────────────────────────────────
      function agPopulateFromAPI() {
        fetch('/api/servers', { credentials: 'include' })
          .then(function(r) { return r.json(); })
          .then(function(d) {
            if (!d.ok || !Array.isArray(d.servers)) return;
            var zone = agGetPreferredZone();
            var servers = d.servers;
            // Filter by zone if selected
            if (zone && d.zones) {
              var zoneServers = d.zones[zone] || d.zones[zone.toLowerCase()];
              if (zoneServers) servers = servers.filter(function(s) { return zoneServers.includes(s.id); });
            }
            sel.innerHTML = '<option value="">&#8212; auto (menor fila) &#8212;</option><option value="random">&#127922; Random</option>';
            servers.forEach(function(s) {
              var opt = document.createElement('option');
              opt.value = String(s.id);
              var load = s.load || (s.full ? 'FULL' : s.queueLength > 0 ? 'MEDIUM' : 'LOW');
              var U = s.full ? ' (cheio)' : s.queueLength > 0 ? ' (fila:'+s.queueLength+')' : ' ✓ LOW';
              opt.textContent = 'Server ' + s.id + U;
              if (String(s.id) === savedServer) opt.selected = true;
              sel.appendChild(opt);
            });
            if (savedServer === 'random') sel.value = 'random';
          }).catch(function() {});
      }
      agPopulateFromAPI();

      // Zone selector change: save + refresh server list
      if (zoneSel) {
        zoneSel.addEventListener('change', function() {
          var z = zoneSel.value;
          try {
            if (z) localStorage.setItem('kintara_ag_preferred_zone', z);
            else localStorage.removeItem('kintara_ag_preferred_zone');
          } catch(_) {}
          agPopulateFromAPI();
        });
      }

      // Server selector change: save
      sel.addEventListener('change', function(e) {
        var v = e.target.value;
        try {
          if (v) localStorage.setItem('kintara_ag_preferred_server', v);
          else localStorage.removeItem('kintara_ag_preferred_server');
        } catch(_) {}
      });

      // ── Auto-join: clica na zona certa e depois no servidor ──────────────
      var _autoJoinTimer = setInterval(function() {
        if (!agActive && !agHuntActive) return;
        if (!agServerScreenVisible()) return;

        var prefZone   = agGetPreferredZone();
        var prefServer = '';
        try { prefServer = localStorage.getItem('kintara_ag_preferred_server') || ''; } catch(_) {}

        var _jcStartup = false;
        try { var _ss = JSON.parse(localStorage.getItem('kintara_ag_startup') || '{}'); _jcStartup = _ss.joinClub === true; } catch(_) {}

        function _isClub(el) {
          var txt = (el.textContent || '').toLowerCase();
          return txt.indexOf('members only') !== -1 ||
                 txt.indexOf('kintara club') !== -1 ||
                 txt.indexOf('tap to subscribe') !== -1 ||
                 txt.indexOf('club only') !== -1 ||
                 txt.indexOf('members-only') !== -1;
        }
        function _isFull(el) {
          var el2 = el;
          for (var d = 0; d < 4 && el2; d++) {
            var txt = (el2.textContent || '').toUpperCase();
            if (txt.includes('FULL') && !txt.includes('QUEUE')) return true;
            el2 = el2.parentElement;
          }
          return el && el.disabled;
        }
        function _getBadge(el) {
          var el2 = el;
          for (var d = 0; d < 4 && el2; d++) {
            var txt = (el2.textContent || '').toUpperCase();
            if (txt.includes('LOW')) return 'LOW';
            if (txt.includes('MEDIUM')) return 'MEDIUM';
            el2 = el2.parentElement;
          }
          return 'MEDIUM';
        }

        // Step 1: click zone button if needed
        var serverItems = agGetServerItems();
        if (!serverItems.length && prefZone) {
          var zoneBtn = agFindZoneBtn(prefZone);
          if (zoneBtn) {
            AG_LOG.info('[AutoJoin] Clicando zona: ' + prefZone);
            zoneBtn.click();
            return; // wait for server list to appear
          }
        }
        // If no zone pref and no servers visible, click first available zone
        if (!serverItems.length) {
          var firstZone = Array.from(document.querySelectorAll('button')).find(function(b) {
            var txt = (b.textContent || '').trim().toUpperCase();
            // Only click actual region zones, never club/premium zones
            return /^(NA|EUR|ASIA|EUROPE|NORTH AMERICA|ASIA PACIFIC)$/.test(txt);
          });
          if (firstZone) { firstZone.click(); return; }
        }

        if (!serverItems.length) return;

        // Step 2: filter eligible servers
        var eligible = serverItems.filter(function(el) {
          if (_isFull(el)) return false;
          if (!_jcStartup && _isClub(el)) return false;
          return true;
        });

        // Step 3: pick server
        var target = null;
        if (prefServer && prefServer !== 'random') {
          // Specific server by number
          target = eligible.find(function(el) {
            var el2 = el; var txt = '';
            for (var d = 0; d < 4 && el2; d++) { txt += ' ' + (el2.textContent || ''); el2 = el2.parentElement; }
            return new RegExp('SERVER\\s*' + prefServer + '\\b', 'i').test(txt);
          });
        }
        if (!target) {
          // Prefer LOW, then last in list (highest ID)
          var lowItems = eligible.filter(function(el) { return _getBadge(el) === 'LOW'; });
          var pool = lowItems.length ? lowItems : eligible;
          target = pool[pool.length - 1];
        }

        if (target) {
          var btn = (target.tagName === 'BUTTON' ? target : target.querySelector('button')) || target;
          AG_LOG.info('[AutoJoin] Entrando: ' + (btn.textContent || '').trim().slice(0,30) + ' (zone=' + (prefZone||'auto') + ')');
          btn.click();
        }
      }, 2500);
    })();

    // ag-server-sel listener moved into loadServers()
    $('ag-server-go').addEventListener('click', function() {
      var v   = $('ag-server-sel') ? $('ag-server-sel').value : '';
      var z   = $('ag-zone-sel')   ? $('ag-zone-sel').value   : '';
      try {
        if (v) localStorage.setItem('kintara_ag_preferred_server', v);
        else localStorage.removeItem('kintara_ag_preferred_server');
        if (z) localStorage.setItem('kintara_ag_preferred_zone', z);
        else localStorage.removeItem('kintara_ag_preferred_zone');
      } catch(_) {}
      agStop();
      var desc = (z ? z + ' ' : '') + (v ? 'Server ' + v : 'auto');
      AG_LOG.info('[AutoJoin] Trocando para: ' + desc);
      var st = $('ag-startup-status');
      if (st) { st.textContent = 'Reconectando → ' + desc + '…'; }
      setTimeout(function() { location.reload(); }, 600);
    });

    // ── Farm realm ────────────────────────────────────────────────────────────
    // ── Performance handlers ─────────────────────────────────────────────
    shadow.querySelectorAll('.ag-pfps').forEach(function(btn) {
      btn.addEventListener('click', function() { agPerfSetFps(parseInt(btn.dataset.fps || 0)); });
    });
    shadow.querySelectorAll('.ag-pqual').forEach(function(btn) {
      btn.addEventListener('click', function() { agPerfSetQuality(btn.dataset.quality); });
    });
    var bgEl = $('ag-perf-bg');
    if (bgEl) bgEl.addEventListener('change', function(e) { agPerfSetBg(e.target.checked); });
    // Inicializar UI v performance
    agPerfUpdateUI();

    var frEl = $('ag-farm-realm');
    if (frEl) frEl.addEventListener('change', function(e) {
      agFarmRealm = e.target.value;
      if (agActive) { if (agFarmRealm) agStartRealmCheck(); else agStopRealmCheck(); }
      agSaveStartupConfig();
    });

    agBtnEl.addEventListener('click', function() { agToggle(); });
    if ($('ag-ver')) $('ag-ver').addEventListener('click', function() { agToggleOptimizedFarm(); });
    $('ag-close').addEventListener('click', function() { agStop(); host.remove(); });

    // ── Import / Export v configurações ─────────────────────────────────────
    (function agSetupCfgIO() {
      var btn = $('ag-cfg-io-btn');
      if (!btn) return;

      var AG_CFG_LS_KEYS = [
        'kintara_ag_startup', 'kintara_ag_autosell', 'kintara_ag_watchdog_ms',
        AG_SERVER_ROTATE_KEY, AG_LAST_ROTATE_KEY, 'kintara_ag_preferred_server', 'kintara_ag_opt_farm',
      ];

      function agExportCfg() {
        var live = {};
        try {
          live.mode      = $('ag-startup-mode')     ? $('ag-startup-mode').value     : undefined;
          live.autostart = $('ag-startup-autostart') ? $('ag-startup-autostart').checked : undefined;
          live.autonav   = $('ag-startup-autonav')   ? $('ag-startup-autonav').checked   : undefined;
          live.autosell  = $('ag-startup-autosell')  ? $('ag-startup-autosell').checked  : undefined;
          live.centercam = $('ag-startup-centercam') ? $('ag-startup-centercam').checked : undefined;
          live.antibot   = $('ag-startup-antibot')   ? $('ag-startup-antibot').checked   : undefined;
          live.freespin  = $('ag-startup-freespin')  ? $('ag-startup-freespin').checked  : undefined;
          live.autogold  = $('ag-startup-autogold')  ? $('ag-startup-autogold').checked  : undefined;
          live.realm     = $('ag-startup-realm')     ? $('ag-startup-realm').value     : undefined;
          live.server    = $('ag-server-sel')        ? $('ag-server-sel').value        : undefined;
          live.serverRotate = (function(){ try { return localStorage.getItem(AG_SERVER_ROTATE_KEY); } catch(_){ return null; } })();
          live.watchdog  = (function(){ try { return localStorage.getItem('kintara_ag_watchdog_ms'); } catch(_){ return null; } })();
        } catch(_) {}
        var d = {};
        AG_CFG_LS_KEYS.forEach(function(k) {
          try { var v = localStorage.getItem(k); if (v !== null) d[k] = v; } catch(_) {}
        });
        return JSON.stringify({ _ag_cfg_version: 1, live: live, localStorage: d }, null, 2);
      }

      function agImportCfg(jsonStr) {
        var cfg;
        try { cfg = JSON.parse(jsonStr); } catch(e) { alert('Erro ao parsear JSON: ' + e.message); return false; }
        if (!cfg || cfg._ag_cfg_version !== 1) { alert('Formato inválido. Use um JSON exportado pelo botão ⚙.'); return false; }
        if (cfg.localStorage && typeof cfg.localStorage === 'object') {
          Object.keys(cfg.localStorage).forEach(function(k) {
            try { localStorage.setItem(k, cfg.localStorage[k]); } catch(_) {}
          });
        }
        var live = cfg.live || {};
        try {
          if (live.mode      !== undefined && $('ag-startup-mode'))     $('ag-startup-mode').value         = live.mode;
          if (live.autostart !== undefined && $('ag-startup-autostart')) $('ag-startup-autostart').checked = !!live.autostart;
          if (live.autonav   !== undefined && $('ag-startup-autonav'))   $('ag-startup-autonav').checked   = !!live.autonav;
          if (live.autosell  !== undefined && $('ag-startup-autosell'))  $('ag-startup-autosell').checked  = !!live.autosell;
          if (live.centercam !== undefined && $('ag-startup-centercam')) $('ag-startup-centercam').checked = !!live.centercam;
          if (live.antibot   !== undefined && $('ag-startup-antibot'))   $('ag-startup-antibot').checked   = live.antibot !== false;
          if (live.freespin  !== undefined && $('ag-startup-freespin'))  $('ag-startup-freespin').checked  = !!live.freespin;
          if (live.autogold  !== undefined && $('ag-startup-autogold'))  $('ag-startup-autogold').checked  = !!live.autogold;
          if (live.realm     !== undefined && $('ag-startup-realm'))     $('ag-startup-realm').value       = live.reacm;
          if (live.server    !== undefined && $('ag-server-sel'))        $('ag-server-sel').value          = live.server;
          if (live.serverRotate !== undefined) { var Gl = $('ag-rotate-sel'); if (rs && live.serverRotate !== null) rs.value = live.serverRotate; }
          if (live.watchdog  !== undefined) { var ws = $('ag-watchdog-sel'); if (ws && live.watchdog !== null) ws.value = live.watchdog; }
        } catch(_) {}
        agSaveStartupConfig();
        return true;
      }

      function agOpenCfgIOModal() {
        var existing = document.getElementById('ag-cfgio-modal-host');
        if (existing) { existing.remove(); return; }
        var host2 = document.createElement('div');
        host2.id = 'ag-cfgio-modal-host';
        host2.attachShadow({ mode: 'open' });
        document.body.appendChild(host2);
        var sr2 = host2.shadowRoot;
        sr2.innerHTML = [
          '<style>',
            '*{box-sizing:border-box;margin:0;padding:0}',
            ':host{position:fixed;top:0;left:0;width:100%;height:100%;display:flex;align-items:center;justify-content:center;z-index:2147483647}',
            '.overlay{position:absolute;inset:0;background:rgba(0,0,0,.65);cursor:pointer}',
            '.modal{position:relative;background:#1a1d2e;border:1px solid rgba(126,184,247,0.25);border-radius:8px;padding:16px;width:420px;max-width:95vw;max-height:90vh;display:flex;flex-direction:column;gap:10px;font-family:monospace;color:#c5cde0;z-index:1}',
            '.modal h3{font-size:13px;font-weight:700;color:#7eb8f7;border-bottom:1px solid rgba(126,184,247,0.15);padding-bottom:6px}',
            '.tabs{display:flex;gap:6px}',
            '.tab{flex:1;padding:5px 0;font-size:11px;font-weight:700;border:1px solid rgba(126,184,247,0.2);border-radius:4px;background:rgba(255,255,255,0.04);color:#8a93a8;cursor:pointer;transition:background .15s}',
            '.tab.active{background:rgba(126,184,247,0.18);color:#7eb8f7;border-color:rgba(126,184,247,0.5)}',
            '.panel{display:none;flex-direction:column;gap:8px}',
            '.panel.visible{display:flex}',
            'textarea{width:100%;height:210px;background:#111320;border:1px solid rgba(126,184,247,0.2);border-radius:4px;color:#c5cde0;font-size:10px;font-family:monospace;padding:8px;resize:vertical;outline:none}',
            '.row{display:flex;gap:6px}',
            '.btn{flex:1;padding:6px 0;font-size:11px;font-weight:700;border-radius:4px;border:none;cursor:pointer;transition:background .15s}',
            '.btn-copy{background:rgba(126,184,247,0.18);color:#7eb8f7}.btn-copy:hover{background:rgba(126,184,247,0.3)}',
            '.btn-import{background:rgba(74,222,128,0.18);color:#4ade80}.btn-import:hover{background:rgba(74,222,128,0.3)}',
            '.btn-cancel{background:rgba(255,255,255,0.07);color:#8a93a8}.btn-cancel:hover{background:rgba(255,255,255,0.14)}',
            '.status{font-size:10px;text-align:center;min-height:14px;color:#4ade80}',
          '</style>',
          '<div class="overlay" id="cfgio-overlay"></div>',
          '<div class="modal">',
            '<h3>&#9881; Importar / Exportar Configurações</h3>',
            '<div class="tabs"><button class="tab active" id="tab-export">&#8593; Exportar</button><button class="tab" id="tab-import">&#8595; Importar</button></div>',
            '<div class="panel visible" id="panel-export"><textarea id="cfgio-export-txt" readonly></textarea>',
              '<div class="row"><button class="btn btn-copy" id="cfgio-copy-btn">&#128203; Copiar</button><button class="btn btn-cancel" id="cfgio-close-btn1">Fechar</button></div></div>',
            '<div class="panel" id="panel-import"><textarea id="cfgio-import-txt" placeholder="Cole aqui o JSON exportado e clique em Importar..."></textarea>',
              '<div class="row"><button class="btn btn-import" id="cfgio-import-btn">&#8595; Importar</button><button class="btn btn-cancel" id="cfgio-close-btn2">Fechar</button></div></div>',
            '<div class="status" id="cfgio-status"></div>',
          '</div>',
        ].join('');

        sr2.getElementById('cfgio-export-txt').value = agExportCfg();

        function closeModal() { host2.remove(); }
        sr2.getElementById('cfgio-overlay').addEventListener('click', closeModal);
        sr2.getElementById('cfgio-close-btn1').addEventListener('click', closeModal);
        sr2.getElementById('cfgio-close-btn2').addEventListener('click', closeModal);

        sr2.getElementById('tab-export').addEventListener('click', function() {
          sr2.getElementById('tab-export').classList.add('active');   sr2.getElementById('tab-import').classList.remove('active');
          sr2.getElementById('panel-export').classList.add('visible'); sr2.getElementById('panel-import').classList.remove('visible');
          sr2.getElementById('cfgio-export-txt').value = agExportCfg();
          sr2.getElementById('cfgio-status').textContent = '';
        });
        sr2.getElementById('tab-import').addEventListener('click', function() {
          sr2.getElementById('tab-import').classList.add('active');   sr2.getElementById('tab-export').classList.remove('active');
          sr2.getElementById('panel-import').classList.add('visible'); sr2.getElementById('panel-export').classList.remove('visible');
          sr2.getElementById('cfgio-status').textContent = '';
        });

        sr2.getElementById('cfgio-copy-btn').addEventListener('click', function() {
          var txt = sr2.getElementById('cfgio-export-txt');
          txt.select();
          try { navigator.clipboard.writeText(txt.value).catch(function() { document.execCommand('copy'); }); } catch(_) { document.execCommand('copy'); }
          var st = sr2.getElementById('cfgio-status');
          st.textContent = '✓ Copiado!';
          setTimeout(function(){ st.textContent = ''; }, 2000);
        });

        sr2.getElementById('cfgio-import-btn').addEventListener('click', function() {
          var txt = sr2.getElementById('cfgio-import-txt').value.trim();
          var st = sr2.getElementById('cfgio-status');
          if (!txt) { st.style.color = '#f87171'; st.textContent = 'Cole o JSON antes v importar.'; return; }
          var ok = agImportCfg(txt);
          if (ok) {
            st.style.color = '#4ade80'; st.textContent = '✓ Configurações importadas com sucesso!';
            setTimeout(function() { closeModal(); }, 1500);
          } else {
            st.style.color = '#f87171'; st.textContent = 'Erro ao importar. Verifique o JSON.';
          }
        });
      }

      btn.addEventListener('click', function(e) { e.stopPropagation(); agOpenCfgIOModal(); });
    })();
    $('ag-mkt-btn').addEventListener('click', function() { agOpenMarketTab(); });
    // Scout HUD toggle button (if exists in panel)
    if ($('ag-scout-btn')) $('ag-scout-btn').addEventListener('click', function() { agScoutHudToggle(); });

  
  // ── Map Info mini HUD ──────────────────────────────────────────────────────
