    var isDrag = false, ox = 0, oy = 0;
    sh.getElementById('sh').addEventListener('mousedown', function(e) {
      if (e.target.id === 'sc') return;
      isDrag = true; ox = e.clientX - host.getBoundingClientRect().left;
      oy = e.clientY - host.getBoundingClientRect().top; e.preventDefault();
    });
    document.addEventListener('mousemove', function(e) {
      if (!isDrag) return;
      host.style.left = (e.clientX - ox) + 'px'; host.style.top = (e.clientY - oy) + 'px';
      host.style.right = 'auto'; host.style.bottom = 'auto';
    });
    document.addEventListener('mouseup', function() { isDrag = false; });

    agScoutHudUpdate();
