  function agScoutHudDestroy() {
    var h = document.getElementById('ag-scout-hud-host');
    if (h) h.remove();
  }

  function agScoutHudToggle() {
    if (document.getElementById('ag-scout-hud-host')) agScoutHudDestroy();
    else agScoutHudCreate();
  }

  function agScoutHudUpdate() {
    var h = document.getElementById('ag-scout-hud-host');
    if (!h) return;
    var sh = h.shadowRoot; if (!sh) return;

    var currentShard = typeof qn === 'function' ? qn() : -1;
    var tabOk = agScoutTabAlive();

    // Status
    var ss = sh.getElementById('ss');
    if (ss) {
      if (_scoutRunning && _scoutCurrent) {
        ss.innerHTML = '<span class="pulse">⟳</span> Escaneando Shard ' + _scoutCurrent + '…';
      } else if (_scoutRunning) {
        ss.innerHTML = '<span class="pulse">⟳</span> Aguardando tab scout…';
      } else if (!tabOk) {
        ss.textContent = '⚠️ Tab Scout não conectada. Clique "Abrir Tab Scout".';
        if (_agScoutTabReady === false && _scoutTabHandle && !_scoutTabHandle.closed) {
          ss.textContent = '⌛ Aguardando tab Scout inicializar…';
        }
      } else {
        var n = Object.keys(_scoutResults).length;
        if (n > 0) {
          var maxTs = Math.max.apply(null, Object.values(_scoutResults).map(function(r) { return r.ts || 0; }));
          var age = Math.round((Date.now() - maxTs) / 60000);
          ss.textContent = '✓ ' + n + ' shards | ' + (age < 1 ? 'agora' : age + 'min atrás') + ' | Tab: #' + (_agScoutTabShard || '?');
        } else {
          ss.textContent = '✓ Tab Scout conectada (shard ' + (_agScoutTabShard || '?') + '). Pronto.';
        }
      }
    }

    // Run button
    var rb = sh.getElementById('rb');
    if (rb) {
      rb.textContent = _scoutRunning ? '⏹ Parar' : '▶ Varrer';
      rb.className   = 'rb' + (_scoutRunning ? ' running' : '');
    }

    // Table
    var tbody = sh.getElementById('tbody');
    if (!tbody) return;
    var filter = _scoutZoneFilter;
    var rows = Object.values(_scoutResults)
      .filter(function(r) { return !filter || r.zone === filter || !r.zone; })
      .sort(function(a, b) { return a.id - b.id; });

    if (!rows.length) {
      tbody.innerHTML = '<tr><td colspan="6" style="text-align:center;color:#475569;padding:10px">' +
        (_scoutRunning ? 'Varrendo…' : 'Nenhum dado. Clique Varrer.') + '</td></tr>';
    } else {
      var minEmber = Math.min.apply(null, rows.map(function(r) { return r.ember; }));
      tbody.innerHTML = rows.map(function(r) {
        var isCur  = r.id === currentShard;
        var isBest = r.ember === minEmber && minEmber === 0;
        var isScan = r.id === _scoutCurrent;
        var rowCls = isCur ? ' class="cur"' : (isBest ? ' class="best"' : '');
        var eCls = r.ember === 0 ? 'sc0' : r.ember <= 2 ? 'sc1' : 'sc2';
        var scanMark = isScan ? ' <span class="pulse" style="color:#fbbf24">⟳</span>' : '';
        var curMark  = isCur  ? ' <span style="color:#a78bfa;font-size:9px">◀</span>' : '';
        return '<tr' + rowCls + '>' +
          '<td><span class="sid">' + r.id + '</span>' + curMark + scanMark + '</td>' +
          '<td><span class="' + eCls + '">' + r.ember + '</span></td>' +
          '<td>' + r.wild + '</td>' +
          '<td>' + r.world + '</td>' +
          '<td>' + r.total + '</td>' +
          '<td><button class="jbtn" data-sid="' + r.id + '">→</button></td>' +
          '</tr>';
      }).join('');

      tbody.querySelectorAll('.jbtn').forEach(function(btn) {
        btn.addEventListener('click', function() {
          var sid = parseInt(btn.getAttribute('data-sid'));
          if (sid > 0 && typeof Z4 === 'function') {
            AG_LOG.info('[Scout] Conectando ao shard ' + sid + '…');
            try { Z4(sid); } catch(_) {}
            try { if (Y && Y.close) Y.close(4003, 'ag_scout_manual'); } catch(_) {}
            setTimeout(function() { try { jY(); } catch(_) {} }, 150);
          }
        });
      });
    }

    // Footer
    var sfi = sh.getElementById('sfi');
    if (sfi) {
      var best = agScoutBestEmberShard(false);
      sfi.textContent = best != null ? '🟢 Melhor Ember: #' + best : (rows.length + ' shards');
    }
  }

