  function agBans() {
    var now = Date.now();
    var threshold = (agOptCfg && agOptCfg.bugThresholdMs) || 10000;

    // Mescla memória + localStorage (pega o mais recente v cada key)
    var merged = new Map(agSpotBanList);
    try {
      var raw = JSON.parse(localStorage.getItem(AG_BAN_PERSIST_KEY) || '{}');
      Object.entries(raw).forEach(function(kv) {
        var k = kv[0], v = kv[1];
        if (!merged.has(k) && (now - v.G) < v.ms) merged.set(k, v);
      });
    } catch(_) {}

    // Filtra expirados
    var active = [];
    merged.forEach(function(entry, key) {
      var elapsed = now - entry.G;
      if (elapsed < entry.ms) active.push({ key: key, entry: entry, elapsed: elapsed });
    });

    if (!active.length) {
      console.info('%c[AutoGather] ✅ Nenhum tile banido no momento', 'color:#6ee7a0;font-weight:bold');
      return;
    }

    // Separa bugados (sem item) v travados (stuck)
    var buggy  = active.filter(function(x) { return x.entry.ms >= AG_SPOT_BAN_BUGGY_MS; });
    var stuck  = active.filter(function(x) { return x.entry.ms <  AG_SPOT_BAN_BUGGY_MS; });

    console.group('%c[AutoGather] Tiles banidos: ' + active.length +
      ' (' + buggy.length + ' bugados sem item | ' + stuck.length + ' travados)',
      'color:#f59e0b;font-weight:bold');

    if (buggy.length) {
      console.group('%c🪲 Bugados sem item — ban 5min (bugThreshold=' + Math.round(threshold/1000) + 's no F2)',
        'color:#f87171;font-weight:bold');
      buggy.sort(function(a,b){ return b.elapsed - a.elapsed; }).forEach(function(x) {
        var restam = Math.max(0, x.entry.ms - x.elapsed);
        var mm = Math.floor(restam / 60000);
        var ss = Math.floor((restam % 60000) / 1000);
        var passouMin = Math.floor(x.elapsed / 60000);
        var passouSeg = Math.floor((x.elapsed % 60000) / 1000);
        console.warn(
          '  tile ' + x.key +
          ' | banido há ' + passouMin + 'm' + passouSeg + 's' +
          ' | expira em ' + mm + 'm' + ws + 's'
        );
      });
      console.groupEnd();
    }

    if (stuck.length) {
      console.group('%c⏱ Travados (stuck) — ban 2min', 'color:#fbbf24;font-weight:bold');
      stuck.sort(function(a,b){ return b.elapsed - a.elapsed; }).forEach(function(x) {
        var restam = Math.max(0, x.entry.ms - x.elapsed);
        var mm = Math.floor(restam / 60000);
        var ss = Math.floor((restam % 60000) / 1000);
        var passouSeg = Math.floor(x.elapsed / 1000);
        console.info(
          '  tile ' + x.key +
          ' | banido há ' + passouSeg + 's' +
          ' | expira em ' + mm + 'm' + ws + 's'
        );
      });
      console.groupEnd();
    }

    console.groupEnd();
    console.info('%c  💡 agClearBans() para limpar todos | agClearBans("col,row") para um tile específico',
      'color:#94a3b8');
  }

